191→        }}
192→        isOption={!isMyOrders}
193→        iconRight="icon-menu"
194→        onPressIconRight={() => setIsMyOrders(true)}
195→      />
196→      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
197→        {hasError ? (
198→          <ErrorState onRetry={() => {}} />
199→        ) : isMyOrders ? (
200→          <CardActivity
201→            isLoading={isLoading}
202→            icon="icon-shopping-bag"
203→            showIcon
204→            showIconRight={false}
205→            hideBackground
206→            hideBorder
207→            title="Meus pedidos"
208→            titleTextType="paragraphXL"
209→            onPress={() => {}}
210→          />
211→        ) : (
212→          <Box ml="smaller" mr="smaller">
213→            <CardPoints
214→              icon="icon-benefits"
215→              iconInfo="icon-help"
216→              iconAction="icon-next"
217→              isLoading={isLoading}
218→              mt="smaller"
219→              mb="xs"
220→              onPressIconInfo={() => {}}
221→              onPressExtract={() => {}}
222→              textExtract="Extrato completo"
223→              title="Pontos disponíveis"
224→              valuePoints={formatPoints(points ?? 0)}
225→            />
226→
227→            <Text type="paragraphXXXL" mb="xxxs">
228→              Onde usar meus pontos
229→            </Text>
230→
231→            <CardMiddle
232→              items={MOCK_ITEMS as PropsCardMiddle['items']}
233→              renderType="grid"
234→              isLoading={isLoading}
